167→export function createStair(startPoint, width = STAIR_WIDTH, numberOfRisers = STAIR_RISERS, riserHeight = STAIR_RISER_HEIGHT, treadDepth = STAIR_TREAD_DEPTH, direction = { angle: 0 }, floorRelation = {}, options = {}) {
168→  return {
169→    id: generateId('stair'),
170→    startPoint: { x: startPoint.x, y: startPoint.y },
171→    width,
