213→export function createSectionCut(startPoint, endPoint, options = {}) {
214→  return {
215→    id: generateId('section'),
216→    startPoint: { x: startPoint.x, y: startPoint.y },
217→    endPoint: { x: endPoint.x, y: endPoint.y },
218→    depth: options.depth ?? SECTION_DEPTH,
219→    label: options.label ?? 'Section A-A',
220→    direction: options.direction ?? 1,
221→  };
222→}
223→
224→export function createRailing(startPoint, endPoint, options = {}) {
225→  return {
226→    id: generateId('rail'),
227→    startPoint: { x: startPoint.x, y: startPoint.y },
228→    endPoint: { x: endPoint.x, y: endPoint.y },
229→    type: options.type ?? 'guardrail',
230→    height: options.height ?? RAILING_HEIGHT,
231→    width: options.width ?? RAILING_WIDTH,
232→  };
233→}
234→
235→export function createRoom(name = 'Room', points = [], color = ROOM_COLOR) {
236→  const area = polygonArea(points);
237→  const centroid = points.length >= 3 ? polygonCentroid(points) : { x: 0, y: 0 };
238→  return {
239→    id: generateId('room'),
240→    name,
241→    points: points.map(p => ({ x: p.x, y: p.y })),
242→    labelPosition: { ...centroid },
243→    color,
244→    area,
245→  };
246→}
