 25→
 26→const ThreePreviewPanel = lazy(() => import('@/three/viewer/ThreePreviewPanel'));
 27→
 28→function EditorShell({
 29→  project,
 30→  handleNew,
 31→  handleSave,
 32→  handleLoadClick,
 33→  isSidebarCollapsed,
 34→  isPropertiesCollapsed,
 35→  onToggleSidebar,
 36→  onToggleProperties,
 37→}) {
 38→  const {
 39→    workspaceMode,
 40→    activeSheetId,
 41→    activeFloorId,
 42→    maximizedPanel,
 43→    dispatch: editorDispatch,
 44→  } = useEditor();
 45→
 46→  useEffect(() => {
 47→    const sheets = project.sheets || [];
 48→    if (!sheets.length) {
 49→      if (activeSheetId !== null) {
 50→        editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: null });
 51→      }
 52→      if (workspaceMode === 'sheet') {
 53→        editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
 54→      }
 55→      return;
 56→    }
 57→
 58→    if (!activeSheetId || !sheets.some((sheet) => sheet.id === activeSheetId)) {
 59→      editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheets[0].id });
 60→    }
 61→  }, [activeSheetId, editorDispatch, project.sheets, workspaceMode]);
 62→
 63→  return (
 64→    <div
 65→      className={styles.layout}
 66→      style={{
 67→        '--layout-sidebar-width': isSidebarCollapsed ? '0px' : 'var(--sidebar-width)',
 68→        '--layout-properties-width': isPropertiesCollapsed ? '0px' : 'var(--properties-width)',
 69→      }}
 70→    >
 71→      <div className={styles.toolbar}>
 72→        <Toolbar
 73→          onNew={handleNew}
 74→          onSave={handleSave}
 75→          onLoad={handleLoadClick}
 76→          isSidebarCollapsed={isSidebarCollapsed}
 77→          isPropertiesCollapsed={isPropertiesCollapsed}
 78→          onToggleSidebar={onToggleSidebar}
 79→          onToggleProperties={onToggleProperties}
 80→        />
 81→      </div>
 82→      <div className={`${styles.sidebar} ${isSidebarCollapsed ? styles.panelHidden : styles.sidebarVisible}`}>
 83→        <Sidebar />
 84→      </div>
 85→      <div className={styles.canvas}>
 86→        {workspaceMode === 'sheet' ? (
 87→          <SheetCanvas />
 88→        ) : (
 89→          <div className={`${styles.modelWorkspace} ${maximizedPanel ? styles.workspaceMaximized : ''}`}>
 90→            {maximizedPanel !== 'preview' && (
 91→              <div className={styles.primaryCanvas}>
 92→                <SvgCanvas />
 93→              </div>
 94→            )}
 95→            {maximizedPanel !== 'canvas' && (
 96→              <div className={styles.preview}>
 97→                <Suspense fallback={<div className={styles.previewFallback}>Loading 3D preview...</div>}>
 98→                  <ThreePreviewPanel
 99→                    project={project}
100→                    activeFloorId={activeFloorId}
101→                    isMaximized={maximizedPanel === 'preview'}
102→                    onToggleMaximize={() => editorDispatch({ type: 'TOGGLE_MAXIMIZE_PANEL', panel: 'preview' })}
103→                  />
104→                </Suspense>
105→              </div>
106→            )}
107→          </div>
108→        )}
109→      </div>
110→      <div className={`${styles.properties} ${isPropertiesCollapsed ? styles.panelHidden : styles.propertiesVisible}`}>
111→        <PropertiesPanel />
112→      </div>
113→    </div>
114→  );
115→}
116→
117→function FloorplanInner({ isPlayground }) {
118→  const { project, isDirty, dispatch } = useProject();
119→  const orderedFloors = useMemo(() => getOrderedFloors(project), [project]);
120→  const availableFloorIds = useMemo(() => orderedFloors.map((floor) => floor.id), [orderedFloors]);
121→  const availablePhaseIds = useMemo(() => (project.phases || []).map((p) => p.id), [project.phases]);
122→  const initialActiveFloorId = getDefaultActiveFloorId(project);
123→  const [showLoadModal, setShowLoadModal] = useState(false);
124→  const [showNewProjectModal, setShowNewProjectModal] = useState(false);
125→  const [savedProjects, setSavedProjects] = useState([]);
126→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
127→  const [isPropertiesCollapsed, setIsPropertiesCollapsed] = useState(false);
128→  const [projectFileHandle, setProjectFileHandle] = useState(null);
129→  const importInputRef = useRef(null);
130→
131→  if (!isPlayground) {
132→    useAutosave(project, isDirty, dispatch);
133→  }
134→
135→  // beforeunload warning
136→  useEffect(() => {
137→    const handler = (e) => {
138→      if (isDirty) {
139→        e.preventDefault();
140→        e.returnValue = '';
141→      }
142→    };
143→    window.addEventListener('beforeunload', handler);
144→    return () => window.removeEventListener('beforeunload', handler);
145→  }, [isDirty]);
146→
147→  const handleNew = useCallback(() => {
148→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
149→    setShowNewProjectModal(true);
150→  }, [isDirty]);
151→
152→  const handleCreateProject = useCallback(({ name }) => {
153→    const newProject = createProject(name);
154→    setProjectFileHandle(null);
155→    dispatch({ type: 'PROJECT_NEW', project: newProject });
156→    setShowNewProjectModal(false);
157→  }, [dispatch]);
158→
159→  const handleSave = useCallback(async () => {
160→    try {
161→      const { fileHandle } = await exportProjectFile(project, { fileHandle: projectFileHandle });
162→      setProjectFileHandle(fileHandle);
163→      try {
164→        await saveProject(project);
165→      } catch {
166→        // Browser draft sync is secondary to file save.
167→      }
168→      dispatch({ type: 'MARK_SAVED' });
169→    } catch (err) {
170→      if (isFilePickerAbortError(err)) return;
171→      alert('Failed to save project file: ' + err.message);
172→    }
173→  }, [project, projectFileHandle, dispatch]);
174→
175→  // Ctrl+S save
176→  useEffect(() => {
177→    const handler = (e) => {
178→      if (isTypingTarget(e.target)) return;
179→      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
180→        e.preventDefault();
181→        handleSave();
182→      }
183→    };
184→    window.addEventListener('keydown', handler);
185→    return () => window.removeEventListener('keydown', handler);
186→  }, [handleSave]);
187→
188→  const handleLoadClick = useCallback(async () => {
189→    setSavedProjects(await listProjects());
190→    setShowLoadModal(true);
191→  }, []);
192→
193→  const handleOpenProjectFile = useCallback(async () => {
194→    if (typeof window.showOpenFilePicker !== 'function') {
195→      importInputRef.current?.click();
196→      return;
197→    }
198→
199→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) {
200→      return;
201→    }
202→
203→    try {
204→      const { project: loaded, savedAt, fileHandle } = await openProjectFile();
205→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
206→      setProjectFileHandle(fileHandle);
207→      setShowLoadModal(false);
208→    } catch (err) {
209→      if (isFilePickerAbortError(err)) return;
210→      alert('Failed to import project file: ' + err.message);
211→    }
212→  }, [isDirty, dispatch]);
213→
214→  const handleImportFile = useCallback(async (e) => {
215→    const file = e.target.files?.[0] || null;
216→    e.target.value = '';
217→    if (!file) return;
218→
219→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) {
220→      return;
221→    }
222→
223→    try {
224→      const { project: loaded, savedAt } = await importProjectFile(file);
225→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
226→      setProjectFileHandle(null);
227→      setShowLoadModal(false);
228→    } catch (err) {
229→      alert('Failed to import project file: ' + err.message);
230→    }
231→  }, [isDirty, dispatch]);
232→
233→  const handleLoad = useCallback(async (id) => {
234→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
235→    try {
236→      const { project: loaded, savedAt } = await loadProject(id);
237→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
238→      setProjectFileHandle(null);
239→      setShowLoadModal(false);
240→    } catch (err) {
241→      alert('Failed to load project: ' + err.message);
242→    }
243→  }, [isDirty, dispatch]);
244→
245→  const handleDelete = useCallback(async (id, name) => {
246→    const confirmed = window.confirm(`Delete "${name}"? This cannot be undone.`);
247→    if (!confirmed) return;
248→
249→    try {
250→      await deleteProject(id);
251→      setSavedProjects(projects => projects.filter(project => project.id !== id));
252→    } catch (err) {
253→      alert('Failed to delete project: ' + err.message);
254→    }
255→  }, []);
256→
257→  return (
258→    <EditorProvider
259→      initialActiveFloorId={initialActiveFloorId}
260→      availableFloorIds={availableFloorIds}
261→      availablePhaseIds={availablePhaseIds}
262→    >
263→      <input
264→        ref={importInputRef}
265→        type="file"
266→        accept=".json,application/json"
267→        onChange={handleImportFile}
268→        style={{ display: 'none' }}
269→      />
270→
271→      <EditorShell
272→        project={project}
273→        handleNew={handleNew}
274→        handleSave={handleSave}
275→        handleLoadClick={handleLoadClick}
276→        isSidebarCollapsed={isSidebarCollapsed}
277→        isPropertiesCollapsed={isPropertiesCollapsed}
278→        onToggleSidebar={() => setIsSidebarCollapsed(value => !value)}
279→        onToggleProperties={() => setIsPropertiesCollapsed(value => !value)}
280→      />
281→
282→      {showNewProjectModal && (
283→        <NewProjectModal
284→          onConfirm={handleCreateProject}
285→          onClose={() => setShowNewProjectModal(false)}
286→        />
287→      )}
288→
289→      {showLoadModal && (
290→        <Modal title="Open Project" onClose={() => setShowLoadModal(false)}>
291→          <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
292→            <div className={modalStyles.modalCard}>
293→              <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
294→                <span className={modalStyles.modalCardTitle}>Project File</span>
295→                <span className={modalStyles.modalCardDesc}>
296→                  Open a JSON file previously saved to your computer.
297→                </span>
298→              </div>
299→              <button className={modalStyles.modalBtn} onClick={handleOpenProjectFile} style={{ alignSelf: 'flex-start' }}>
300→                Open Project File
301→              </button>
302→            </div>
303→
304→            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
305→              <div style={{ display: 'flex', flexDirection: 'column', gap: '2px' }}>
306→                <span className={modalStyles.modalCardTitle}>Browser Drafts</span>
307→                <span className={modalStyles.modalCardDesc} style={{ fontSize: '11px' }}>
308→                  Stored only in this browser on this machine.
309→                </span>
310→              </div>
311→              {savedProjects.length === 0 ? (
312→                <p style={{ color: 'var(--color-text-secondary)', fontSize: '13px', margin: 0 }}>
313→                  No browser drafts found.
314→                </p>
315→              ) : (
316→                <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
317→                  {savedProjects.map(p => (
318→                    <div key={p.id} className={modalStyles.modalCard} style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center' }}>
319→                      <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
320→                        <span style={{ fontWeight: 500, fontSize: '13px' }}>{p.name}</span>
321→                        <span style={{ color: 'var(--color-text-secondary)', fontSize: '11px' }}>
322→                          {new Date(p.savedAt).toLocaleDateString()}
323→                        </span>
324→                      </div>
325→                      <div style={{ display: 'flex', gap: '8px' }}>
326→                        <button className={modalStyles.modalBtn} onClick={() => handleLoad(p.id)}>Load</button>
327→                        <button className={modalStyles.modalBtnDanger} onClick={() => handleDelete(p.id, p.name)}>Delete</button>
328→                      </div>
329→                    </div>
330→                  ))}
331→                </div>
332→              )}
333→            </div>
334→          </div>
335→          <button className={modalStyles.modalBtn} onClick={() => setShowLoadModal(false)} style={{ marginTop: '16px' }}>
336→            Cancel
337→          </button>
338→        </Modal>
339→      )}
340→    </EditorProvider>
341→  );
342→}
343→
344→export default function FloorplanWorkspace({ initialProject, isPlayground = false }) {
345→  return (
346→    <div className="editorRoot">
347→      <ProjectProvider initialProject={initialProject}>
348→        <ClipboardProvider>
349→          <FloorplanInner isPlayground={isPlayground} />
350→        </ClipboardProvider>
351→      </ProjectProvider>
352→    </div>
353→  );
354→}
